Here's a modern MSTest approach using `HttpMessageHandler` mocking, async test methods, and cancellation testing:

```csharp
using System.Net;
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_OnNonSuccessStatus()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)] // fails test if it hangs longer than 5s
    public async Task FetchAsync_HonoursCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("data")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_CancelsDuringRequest()
    {
        using var cts = new CancellationTokenSource();
        var handler = new DelayedHandler(cts);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Minimal fake handler for deterministic responses
    private class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage _response;
        public FakeHandler(HttpResponseMessage response) => _response = response;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(_response);
        }
    }

    // Simulates a slow response, then cancels mid-flight
    private class DelayedHandler : HttpMessageHandler
    {
        private readonly CancellationTokenSource _cts;
        public DelayedHandler(CancellationTokenSource cts) => _cts = cts;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            _cts.CancelAfter(50); // cancel shortly after request starts
            await Task.Delay(10_000, cancellationToken); // will be interrupted
            return new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---------|-----|
| `async Task` test methods | MSTest natively awaits them — no `.Result` deadlocks |
| `[Timeout(ms)]` | Guards against hangs; fails deterministically |
| `ThrowsExceptionAsync` | Proper async exception assertion |
| Pre-cancelled token | Verifies immediate cancellation path |
| `CancelAfter` in handler | Verifies mid-flight cancellation |
| Custom `HttpMessageHandler` | No mocking library needed; full control over `HttpClient` behavior |

This avoids the common antipatterns of blocking on `.Result`/`.Wait()` and testing cancellation only at the surface level.
